#include <stdio.h>
int isBST(int* arr, int n) {
    int prev = -1;
    for (int i = 0; i < n; i++) {
        if (arr[i] < prev) return 0;
        prev = arr[i];
    }
    return 1;
}
int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n;
        scanf("%d", &n);
        int arr[n];
        for (int i = 0; i < n; i++) scanf("%d", &arr[i]);
        printf("%d\n", isBST(arr, n));
    }
    return 0;
}

